// // This module is designed to decrement its output on each rising edge of the clock signal and reset to 7 when the reset input is asserted.
module top_module(
    input clk,
    input reset,
    output reg [2:0] out
  );always @(posedge clk) begin
    if (reset) begin
      out <= 0;
    end else begin
      out <= out + 1;
    end
  end

endmodule
